import React, { useState, useEffect } from "react";
import { Edit2, Trash2 } from "lucide-react";
import { getBatches, updateBatch, deleteBatch } from "../../services/api";
import Swal from "sweetalert2";
import DataEntryTable from "../ui/table";

export default function Batches({ searchQuery, refreshTrigger }) {
  const [batches, setBatches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState(null);
  const [showPopup, setShowPopup] = useState(false);
  const [popupTitle, setPopupTitle] = useState("");
  const [popupItems, setPopupItems] = useState([]);

  const columns = [
    { key: "degree", label: "Degree / Course" },
    { key: "batchCode", label: "Batch code" },
    { key: "department", label: "Department" },
    { key: "capacity", label: "Capacity" },
    { key: "semester", label: "Semester" },
    { key: "section", label: "Section" },
    { key: "subjects", label: "Assigned Subjects" },
  ];

  useEffect(() => {
    fetchBatches();
  }, [refreshTrigger]);

  const fetchBatches = async () => {
    try {
      setLoading(true);
      const response = await getBatches();
      setBatches(response.data || []);
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (batchId) => {
    const result = await Swal.fire({
      text: "Are you sure you want to delete this batch?",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#F04438",
      cancelButtonColor: "#4BACCE",
      confirmButtonText: "Yes, delete",
    });

    if (!result.isConfirmed) return;

    await deleteBatch(batchId);
    fetchBatches();
  };

  const handleEdit = (batch) => {
    setEditingId(batch._id);
    setEditData({ ...batch });
  };

  const handleUpdate = async () => {
    const response = await updateBatch(editingId, editData);
    const updated = response?.data || editData;

    setBatches((prev) =>
      prev.map((b) => (b._id === editingId ? updated : b))
    );

    setEditingId(null);
    setEditData(null);
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditData(null);
  };

  const openListPopup = (title, items) => {
    setPopupTitle(title);
    setPopupItems(Array.isArray(items) ? items : []);
    setShowPopup(true);
  };

  const q = (searchQuery || "").toLowerCase();
  const filtered = batches.filter(
    (b) =>
      (b.degree || "").toLowerCase().includes(q) ||
      (b.batchCode || "").toLowerCase().includes(q) ||
      (b.department || "").toLowerCase().includes(q)
  );

  return (
    <>
      <DataEntryTable columns={columns}>
        {loading && (
          <tr>
            <td colSpan={8} className="py-10 text-center text-[#8A96A8]">
              Loading batches...
            </td>
          </tr>
        )}

        {!loading &&
          filtered.map((item, idx) => (
            <tr
              key={item._id}
              className={`text-sm border-b border-[#ECF0F4] hover:bg-[#F7FAFF] transition ${
                idx === filtered.length - 1 ? "border-b-0" : ""
              }`}
            >
              <td className="py-5 text-center text-[#4C5968]">
                {editingId === item._id ? (
                  <input
                    value={editData.degree}
                    onChange={(e) =>
                      setEditData({ ...editData, degree: e.target.value })
                    }
                    className="w-[180px] px-2 py-1 border rounded text-center"
                  />
                ) : (
                  item.degree || "N/A"
                )}
              </td>

              <td className="py-5 text-center text-[#8A96A8]">
                {editingId === item._id ? (
                  <input
                    value={editData.batchCode}
                    onChange={(e) =>
                      setEditData({ ...editData, batchCode: e.target.value })
                    }
                    className="w-[120px] px-2 py-1 border rounded text-center"
                  />
                ) : (
                  item.batchCode || "N/A"
                )}
              </td>

              <td className="py-5 text-center text-[#8A96A8]">
                {editingId === item._id ? (
                  <input
                    value={editData.department}
                    onChange={(e) =>
                      setEditData({ ...editData, department: e.target.value })
                    }
                    className="w-[180px] px-2 py-1 border rounded text-center"
                  />
                ) : (
                  item.department || "N/A"
                )}
              </td>

              <td className="py-5 text-center text-[#8A96A8]">
                {editingId === item._id ? (
                  <input
                    value={editData.capacity}
                    onChange={(e) =>
                      setEditData({ ...editData, capacity: e.target.value })
                    }
                    className="w-[110px] px-2 py-1 border rounded text-center"
                  />
                ) : (
                  item.capacity || item.strength || "N/A"
                )}
              </td>

              <td className="py-5 text-center text-[#8A96A8]">
                {editingId === item._id ? (
                  <input
                    value={editData.semester}
                    onChange={(e) =>
                      setEditData({ ...editData, semester: e.target.value })
                    }
                    className="w-[110px] px-2 py-1 border rounded text-center"
                  />
                ) : (
                  item.semester || "N/A"
                )}
              </td>

              <td className="py-5 text-center text-[#8A96A8]">
                {item.batchCode?.split("_")[2] || "A"}
              </td>

              <td className="py-5 text-center">
                {(item.raw?.subjects || item.subjects || []).length > 0 ? (
                  <button
                    onClick={() =>
                      openListPopup(
                        "Assigned Subjects",
                        (item.raw?.subjects || item.subjects || []).map(
                          (s) =>
                            typeof s.subject === "object" ? s.subject : s
                        )
                      )
                    }
                    className="text-[#1A8FE3] hover:underline text-[13px] font-medium"
                  >
                    See List ({(item.raw?.subjects || item.subjects).length})
                  </button>
                ) : (
                  "None"
                )}
              </td>

              <td className="py-5">
                {editingId === item._id ? (
                  <div className="flex justify-center gap-2">
                    <button onClick={handleUpdate} className="text-[#1A8FE3]">
                      Save
                    </button>
                    <button onClick={handleCancelEdit} className="text-[#8A96A8]">
                      Cancel
                    </button>
                  </div>
                ) : (
                  <div className="flex justify-center gap-3">
                    <button
                      onClick={() => handleEdit(item)}
                      className="text-[rgba(38,87,104,0.5)] hover:text-[rgba(38,87,104,0.8)]"
                    >
                      <Edit2 size={15} strokeWidth={1.5} />
                    </button>

                    <button
                      onClick={() => handleDelete(item._id)}
                      className="text-[rgba(38,87,104,0.5)] hover:text-[rgba(38,87,104,0.8)]"
                    >
                      <Trash2 size={15} strokeWidth={1.5} />
                    </button>
                  </div>
                )}
              </td>
            </tr>
          ))}
      </DataEntryTable>

      {showPopup && (
        <div
          className="fixed inset-0 z-[999] flex items-center justify-center"
          style={{ background: "rgba(0,0,0,0.35)" }}
          onClick={() => setShowPopup(false)}
        >
          <div
            className="bg-white rounded-[10px] shadow-lg border"
            style={{ width: 420, maxHeight: 420 }}
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex justify-between px-5 py-3 border-b">
              <div className="font-semibold text-[#265768]">{popupTitle}</div>
              <button onClick={() => setShowPopup(false)}>✕</button>
            </div>

            <div className="p-4 overflow-y-auto" style={{ maxHeight: 340 }}>
              <ul className="space-y-2">
                {popupItems.map((x, i) => (
                  <li
                    key={i}
                    className="text-[13px] text-[#265768] border rounded px-3 py-2"
                  >
                    {x?.name || "-"} {x?.code ? `(${x.code})` : ""}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      )}
    </>
  );
}




















