import React, { useState } from "react";
import { CreditCard, Key } from "lucide-react";
import { CardContainer } from "./CardContainer";
import { InputField } from "../../components/ui/InputField";
import { Button } from "../../components/ui/Button";
import { Footer } from "./Footer";
import { useNavigate } from "react-router-dom";

export const ERPConnectionScreen = ({ onNext }) => {
  const [erpId, setErpId] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  return (
    <CardContainer title="Connect your ERP to automatically sync faculty, timetable,  and classroom data — no manual setup required">
      <div className="max-w-2xl mx-auto px-4 sm:px-8 py-6 sm:py-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8 mb-8 mt-3">
          <InputField
            label="ENTER ERP ID"
            value={erpId}
            onChange={(e) => setErpId(e.target.value)}
            placeholder="e.g. A6BZU55"
            icon={CreditCard}
          />

          <InputField
            label="ENTER PASSWORD"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="••••••••••"
            icon={Key}
            showPasswordToggle={true}
            showPassword={showPassword}
            onTogglePassword={() => setShowPassword(!showPassword)}
          />
        </div>

        <div className="flex justify-center items-center md:mr-4">
          <Button onClick={() => navigate("/dashboard")}>Connect ERP</Button>
        </div>
      </div>

      <Footer />
    </CardContainer>
  );
};

import React, { useState } from "react";
import { CardContainer } from "./CardContainer";
import { Button } from "../../components/ui/Button";
import { Footer } from "./Footer";
import { useNavigate } from "react-router-dom";

export const LoadchartScreen = ({ onNext }) => {
  const [dragActive, setDragActive] = useState(false);
  const navigate = useNavigate();

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
  };

  return (
    <CardContainer title="Ready to upload the loadchart? We'll extract faculty assignments and class loads for scheduling">
      <div className="max-w-md mx-auto">
        {/* ✅ Smaller dotted box */}
        <div
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
          className={`
            border-2 border-dashed rounded-[6px]
            px-6 py-1 text-center transition-all duration-300
            w-[280px] mx-auto mb-5
            ${dragActive ? "border-[#4BACCE] bg-[#F3FBFF]" : "border-[#87BFD2] bg-white"}
          `}
        >
          {/* ✅ Image style block */}
          <div className="flex justify-center mb-8 pb-5">
            <div className="relative w-[100px] h-[20px] drop-shadow-[0px_4px_4px_#00000040]">
              {/* 🔘 BIG GREY IMAGE (background box) */}
              <img
                src="/rectangle.png"
                alt="grey box"
                className="absolute left-0 top-3 w-[120px] h-[40px] object-contain hover:drop-shadow-[0px_4px_4px_#00000040]"
              />

              {/* 🔹 Small top box 1 */}
              <img
                src="/box.png"
                alt="small box 1"
                className="
                  absolute  right-[40px] top-[10px]
                  w-[90px] h-[30px] object-contain
                  hover:drop-shadow-[0px_4px_4px_#00000040]
                "
              />

              {/* 🔹 Small top box 2 */}
              <img
                src="/box.png"
                alt="small box 2"
                className="
                  absolute left-[50px] top-[30px]
                  w-[90px] h-[30px] object-contain
                  hover:drop-shadow-[0px_4px_4px_#00000040]
                "
              />
            </div>
          </div>

          <p className="text-[#265768] font-medium mb-1 text-[12px]">
            Drag and drop loadset file to upload
          </p>

          <p className="text-[#8AA6B1] text-[10px] mb-1">
            Upload file in Excel / Word form
          </p>

          <Button variant="secondary" className="w-[80px] mx-auto mt-2 text-[8px] py-1">
            Browse File
          </Button>
        </div>
      </div>

      <div className="flex justify-center items-center">
        <Button onClick={() => navigate("/dashboard")}>Connect ERP</Button>
      </div>

      <Footer />
    </CardContainer>
  );
};

import React, { useEffect, useState } from "react";
import { Mail, Lock } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { loginAPI } from "../../services/api";
import { Button } from "../../components/ui/Button";
import { InputField } from "../../components/ui/InputField";
import Swal from "sweetalert2";

const LoginForm = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const handleSubmit = async () => {
    if (!email || !password) {
      Swal.fire({
        icon: "warning",
        text: "Please enter email and password",
        confirmButtonColor: "#4BACCE",
      });
      return;
    }

    setLoading(true);
    try {
      const res = await loginAPI(email, password);

      if (res.success) {
        if (res.token) {
          localStorage.setItem("token", res.token);
        }

        Swal.fire({
          title: "Success!",
          text: "Login Successful",
          icon: "success",
          confirmButtonColor: "#4BACCE",
        }).then(() => {
          if (res.user?.isNewUser) {
            navigate("/form");
          } else {
            navigate("/dashboard");
          }
        });
      } else {
        Swal.fire({
          icon: "error",
          text: res.message || "Login failed",
          confirmButtonColor: "#4BACCE",
        });
      }
    } catch (error) {
      console.error(error);
      Swal.fire({
        icon: "error",
        text: error.message || "Something went wrong",
        confirmButtonColor: "#4BACCE",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div className="mb-8 text-center">
        <p className="text-lg font-semibold text-[#4A9FB5] text-left mb-8 -ml-6 -mt-2">
          Ezey
        </p>

        <h1
          className="mb-3"
          style={{
            fontFamily: "Georgia, serif",
            fontWeight: 700,
            fontSize: "28px",
            lineHeight: "120%",
            color: "#265768",
          }}
        >
          Welcome to Ezey
        </h1>

        <p className="text-sm text-[#7A8C94]">
          Start your experience with Ezey by signing in
        </p>
        <p className="text-sm text-[#7A8C94]">or signing up</p>
      </div>

      <div className="mb-4">
        <InputField
          width="450px"
          height="42px"
          label="Email Address / Institution Id"
          type="text"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="Enter Email Address or Institution Id"
          icon={Mail}
        />
      </div>

      <div className="mb-2 mt-3 relative">
        <InputField
          width="450px"
          height="42px"
          label="Password*"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          placeholder="************"
          icon={Lock}
          showPasswordToggle
          showPassword={showPassword}
          onTogglePassword={() => setShowPassword(!showPassword)}
        />

        <span className="absolute right-[40px] top-[33px] text-[#7A8C94] pointer-events-none">
          |
        </span>

        <p
          onClick={() => navigate("/forgetpassword")}
          className="text-xs text-[#4A9FB5] mt-1 cursor-pointer pr-1 mb-12 relative w-fit ml-auto"
        >
          Forgot Password?
        </p>
      </div>

      <div className="flex justify-end mb-2 mr-10">
        <p className="text-xs text-[#7A8C94]">
          New user ?{" "}
          <span
            onClick={() => navigate("/signup")}
            className="text-[#4A9FB5] cursor-pointer"
          >
            Sign Up
          </span>
        </p>
      </div>

      <div className="flex justify-center mb-6 mt-2">
        <Button
          variant="primary"
          onClick={handleSubmit}
          className={loading ? "opacity-70 pointer-events-none" : ""}
        >
          {loading ? "Signing In..." : "Sign In"}
        </Button>
      </div>
    </>
  );
};

export default LoginForm;












