import React, { useEffect, useState } from "react";

const RightAuthSlider = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    {
      text: "With Ezey, your timing manual timetable arrangement becomes fully automated!",
    },
    {
      text: "Collaborate seamlessly with your team",
    },
    {
      text: "Save time with automated scheduling",
    },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div
      className="relative w-full h-[630px] rounded-2xl overflow-hidden shadow-xl flex items-center justify-center"
      style={{
        backgroundImage: "url('/rightbg.jpg')",
        backgroundSize: "cover",
        backgroundPosition: "center",
      }}
    >
      <div className="absolute inset-0 bg-black/40" />

      {slides.map((slide, index) => (
        <div
          key={index}
          className={`absolute inset-0 flex flex-col items-center justify-center transition-opacity duration-1000 ${currentSlide === index ? "opacity-100" : "opacity-0"
            }`}
        >
          <div className="relative w-[360px] h-[400px] mb-8">
            {index === 0 && (
              <>
                <img
                  src="/spects.jpg"
                  className="absolute top-0 right-10 w-44 h-44 rounded-2xl border-8 border-[#599BAB]/50 object-cover"
                />

                <img
                  src="/watch.jpg"
                  className="absolute inset-1/2 -translate-x-1/2 -translate-y-1/2 w-44 h-44 rounded-2xl border-8 border-[#599BAB]/50 object-cover"
                />

                <img
                  src="/copy.jpg"
                  className="absolute bottom-0 left-6 w-44 h-44 rounded-2xl border-8 border-[#599BAB]/50 object-cover"
                />
              </>
            )}

            {index !== 0 && (
              <img
                src={index === 1 ? "/ezeyteam.jpg" : "/timer.jpg"}
                className="absolute inset-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 rounded-2xl border-8 border-[#599BAB]/50 object-cover"
              />
            )}
          </div>

          <p className="text-white text-xl text-center max-w-md px-6">
            "{slide.text}"
          </p>
        </div>
      ))}

      <div className="absolute bottom-6 flex gap-2">
        {slides.map((_, i) => (
          <button
            key={i}
            onClick={() => setCurrentSlide(i)}
            className={`h-2 rounded-full transition-all ${currentSlide === i ? "w-8 bg-white" : "w-2 bg-white/50"
              }`}
          />
        ))}
      </div>
    </div>
  );
};

export default RightAuthSlider;

import React, { useEffect, useState, useRef } from "react";
import {
  getBatches,
  getTimetablePreviewAPI,
  getTimetableVisualHTML,
  generateTimetable,
} from "../../services/api";
import { Button } from "../../components/ui/Button";
import { useNavigate } from "react-router-dom";
import Swal from "sweetalert2";


export default function GenerateTT() {
  const [activeTab, setActiveTab] = useState("generate");
  const dropdownRef = useRef(null);

  // ✅ dropdown input text
  const [searchText, setSearchText] = useState("");

  // ✅ selected batchId (this is what backend needs)
  const [selectedBatchId, setSelectedBatchId] = useState("");

  // ✅ dropdown control
  const [showDropdown, setShowDropdown] = useState(false);

  // ✅ batches list from API
  const [batchOptions, setBatchOptions] = useState([]);
  const [batchLoading, setBatchLoading] = useState(false);

  // generate api loader
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  // ✅ preview api states
  const [previewLoading, setPreviewLoading] = useState(false);
  const [previewError, setPreviewError] = useState("");
  const [previewData, setPreviewData] = useState(null);

  // =====================================================
  // ✅ Fetch batches from API (for dropdown)
  // =====================================================
  useEffect(() => {
    const fetchBatches = async () => {
      try {
        setBatchLoading(true);
        const res = await getBatches();

        if (res?.success) {
          setBatchOptions(res.data || []);
        } else {
          setBatchOptions([]);
        }
      } catch (err) {
        console.error("Failed to fetch batches:", err);
        setBatchOptions([]);
      } finally {
        setBatchLoading(false);
      }
    };

    fetchBatches();

    // ✅ Click outside handler to close dropdown
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setShowDropdown(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleGenerate = async () => {
    if (!selectedBatchId) {
      Swal.fire({
        icon: "warning",
        text: "Please select batch from dropdown",
        confirmButtonColor: "#4BACCE",
      });
      return;
    }

    try {
      setLoading(true);

      // Call the generate timetable API
      await generateTimetable(selectedBatchId);

      Swal.fire({
        icon: "success",
        text: "Timetable generated successfully!",
        confirmButtonColor: "#4BACCE",
      });

    } catch (err) {
      console.error(err);
      Swal.fire({
        icon: "error",
        text: err.message || "Failed to generate timetable",
        confirmButtonColor: "#4BACCE",
      });
    } finally {
      setLoading(false);
    }
  };


  // =====================================================
  // ✅ Preview Tab fetch old timetable list
  // =====================================================
  const handlePreviewTabClick = async () => {
    setActiveTab("preview");

    try {
      setPreviewLoading(true);
      setPreviewError("");

      const res = await getTimetablePreviewAPI();
      setPreviewData(res);
    } catch (err) {
      console.error(err);
      setPreviewError("Failed to fetch preview timetable");
    } finally {
      setPreviewLoading(false);
    }
  };

  // =====================================================
  // ✅ helper for display label
  // =====================================================


  const formatBatchLabel = (b) => {
    const course = b?.course || b?.degree || "-";
    const department = b?.department || "-";
    const section = b?.name || b?.section || "-";
    const semester = b?.semester ?? "-";
    return `${course} - ${department} - ${section} (Semester ${semester})`;
  };


  return (
    // ✅ CardContainer wrapper removed (to avoid double card)
    <div className="w-full h-full min-h-[calc(95vh-180px)] flex flex-col">
      {/* ===== Header ===== */}
      <section className="mb-6 flex items-start justify-between gap-8">
        <div>
          <h1
            className="text-[32px] leading-tight font-bold text-[#265768] mb-2"
            style={{ fontFamily: "Playfair Display, serif" }}
          >
            View / Edit generated schedules
          </h1>

          <p
            className="text-sm text-[#265768] max-w-3xl"
            style={{ fontFamily: "Mulish, sans-serif" }}
          >
            Generate and preview timetables using batch ID
          </p>
        </div>
      </section>

      {/* ===== Tabs ===== */}
      <div className="flex gap-8 border-b border-[#E5E7EB] mb-6 relative">
        {/* Generate Tab */}
        <button
          onClick={() => setActiveTab("generate")}
          className={`relative px-4 pb-3 text-[14px] font-medium leading-[150%] text-center font-mulish
          ${activeTab === "generate" ? "text-[#265768]" : "text-[#9CA3AF]"}`}
        >
          Generate Timetable
          {activeTab === "generate" && (
            <span
              className="absolute left-1/2 -translate-x-1/2 -bottom-[2px]
              w-[149px] h-[4px] border-2 border-[#0891B2] bg-[#0077FF]
              rounded-[27px]"
            />
          )}
        </button>

        {/* Preview Tab */}
        <button
          onClick={handlePreviewTabClick}
          className={`relative px-4 pb-3 text-[14px] font-medium leading-[150%] text-center font-mulish
          ${activeTab === "preview" ? "text-[#265768]" : "text-[#9CA3AF]"}`}
        >
          Preview Timetable
          {activeTab === "preview" && (
            <span
              className="absolute left-1/2 -translate-x-1/2 -bottom-[2px]
              w-[149px] h-[4px] border-2 border-[#0891B2] bg-[#0077FF]
              rounded-[27px]"
            />
          )}
        </button>
      </div>

      {/* ============================= */}
      {/* ✅ Generate tab (UI SAME) */}
      {/* ============================= */}
      {activeTab === "generate" && (
        <>
          {/* Search + Generate */}
          <div className="mb-6 flex items-end gap-10">
            {/* Search */}
            <div className="flex-1 max-w-[900px]" ref={dropdownRef}>
              {/* <label className="block text-xs font-medium text-[#374151] mb-2">
                Search Batch
              </label> */}

              <div className="relative bg-[#F7FAFD] border border-[#BFBFBF] rounded-[16px] px-4 py-2.5 mr-20">
                {/* Search Icon */}
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-[#9AA5B6]"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M21 21l-4.35-4.35M10 18a8 8 0 100-16 8 8 0 000 16z"
                  />
                </svg>

                <input
                  type="text"
                  value={searchText}
                  onChange={(e) => {
                    setSearchText(e.target.value);
                    setShowDropdown(true);

                    // ✅ IMPORTANT: if user edits manually, clear selected id
                    setSelectedBatchId("");
                  }}
                  onFocus={() => setShowDropdown(true)}
                  placeholder="Search batch (course / code / semester)"
                  className="w-full bg-transparent pl-7 pr-28 text-sm text-[#374151]
                  placeholder:text-[#265768] focus:outline-none"
                />

                {/* Add Batch Button */}
                <button
                  onClick={() => navigate("/manual/batches")}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-[13px] font-medium text-[#4BACCE] hover:text-[#265768] transition-colors"
                >
                  + Add batch
                </button>

                {/* Dropdown */}
                {showDropdown && (
                  <div
                    className="absolute left-0 right-0 top-full mt-2 bg-white
                    border border-[#E5E7EB] rounded-[10px] shadow-lg z-10 
                    max-h-40 overflow-y-auto"
                  >
                    {batchLoading && (
                      <div className="px-4 py-2 text-xs text-[#9CA3AF]">
                        Loading batches...
                      </div>
                    )}

                    {!batchLoading &&
                      batchOptions
                        .filter((b) => {
                          const label = formatBatchLabel(b).toLowerCase();
                          return label.includes(searchText.toLowerCase());
                        })
                        .map((b) => (
                          <div
                            key={b._id}
                            onClick={() => {
                              // ✅ show label to user
                              setSearchText(formatBatchLabel(b));

                              // ✅ backend ko sirf id jayegi
                              setSelectedBatchId(b._id);

                              setShowDropdown(false);
                            }}
                            className="px-4 py-2 text-sm cursor-pointer
                            hover:bg-[#F7FAFD] text-[#374151]"
                          >
                            {formatBatchLabel(b)}
                          </div>
                        ))}

                    {!batchLoading &&
                      batchOptions.filter((b) =>
                        formatBatchLabel(b)
                          .toLowerCase()
                          .includes(searchText.toLowerCase())
                      ).length === 0 && (
                        <div className="px-4 py-2 text-xs text-[#9CA3AF]">
                          No results found
                        </div>
                      )}
                  </div>
                )}
              </div>
            </div>

            {/* Generate Button */}
            <Button
              variant="primary"
              onClick={handleGenerate}
              className="!w-[250px] !h-[42px] !text-[16px]"
            >
              {loading ? "Generating..." : "Generate Timetable"}
            </Button>
          </div>
        </>
      )}

      {/* ============================= */}
      {/* ✅ Preview tab (TABLE UI) */}
      {/* ============================= */}
      {activeTab === "preview" && (
        <div className="mt-4">
          {previewLoading && (
            <p className="text-[#265768] font-semibold">Loading preview...</p>
          )}

          {previewError && (
            <p className="text-red-500 font-semibold">{previewError}</p>
          )}

          {!previewLoading &&
            !previewError &&
            previewData?.data?.length === 0 && (
              <p className="text-[#9CA3AF] font-semibold">
                No generated timetable found.
              </p>
            )}

          {!previewLoading &&
            !previewError &&
            previewData?.data?.length > 0 && (
              <div
                className="bg-white w-full relative mt-6"
                style={{
                  width: "100%",
                  borderRadius: "12.23px",
                  border: "1.83px solid #DFDFDF",
                  overflow: "hidden",
                  backgroundColor: "white",
                }}
              >
                {/* Header */}
                <div className="px-8 pt-3 pb-1 bg-white">
                  <div
                    className="flex items-center text-[14px] font-medium"
                    style={{
                      color: "#265768",
                      fontFamily: "'Mulish', sans-serif",
                    }}
                  >
                    <div className="flex-1 text-left">Degree / Course</div>
                    <div className="flex-1 text-center">Department</div>
                    <div className="flex-1 text-center">Semester</div>
                    <div className="flex-1 text-center">Section</div>
                    <div className="flex-1 text-center">Preview Timetable</div>
                  </div>

                  {/* Blue underline */}
                  <div
                    className="mt-2 h-[1.5px] rounded"
                    style={{
                      background: "#0b84d6",
                      boxShadow: "0px 4px 4px 0px rgba(0,0,0,0.25)",
                    }}
                  />
                </div>

                {/* Rows */}
                <div className="px-8">
                  {previewData.data.map((tt) => {
                    const batch = tt?.batch;
                    const section =
                      typeof batch?.code === "string" && batch.code.length > 0
                        ? batch.code.slice(-1)
                        : "-";

                    return (
                      <div
                        key={tt._id}
                        className="flex items-center py-3.5 hover:bg-gray-50 transition"
                        style={{ borderBottom: "3px solid #D9D9D9" }}
                      >
                        <div className="flex-1 text-[13px] font-medium text-[#265768]/60 text-left">
                          {batch?.name || "-"}
                        </div>

                        <div className="flex-1 text-[13px] text-[#265768]/60 text-center">
                          {batch?.department || "-"}
                        </div>

                        <div className="flex-1 text-[13px] text-[#265768]/60 text-center">
                          {batch?.semester ?? "-"}
                        </div>

                        <div className="flex-1 text-[13px] text-[#265768]/60 text-center">
                          {section}
                        </div>

                        <div
                          className="flex-1 text-[13px] text-[#4BACCE]/60 cursor-pointer hover:underline text-center"
                          title="Preview Timetable"
                          onClick={() => {
                            const url = `http://localhost:5000/timetable/visual/${batch?._id}`;
                            window.open(url, "_blank", "noopener,noreferrer");
                          }}
                        >
                          📅
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
        </div>
      )}
    </div>
  );
}

import React, { useRef, useState, useEffect } from "react";
import { Edit2, Trash2, X } from "lucide-react";
import nodata from "../../assets/images/nodataa.png";
import {
  getBatches,
  addBatch as addBatchAPI,
  updateBatch,
  deleteBatch,
  getSubjects,
  getFaculties,
} from "../../services/api";
import { useNavigate } from "react-router-dom";
import BackButton from "../../components/backbutton";
import Swal from "sweetalert2";

// ============================================
// MULTISELECT COMPONENT
// ============================================
function MultiSelect({
  label,
  placeholder,
  options,
  selectedItems,
  onToggle,
  onRemove,
  displayKey = "name",
  secondaryKey = null,
  additionalKeys = [],
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
        setSearchTerm("");
      }
    };
    if (isOpen) {
      document.addEventListener("mousedown", handleClickOutside);
    }
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [isOpen]);

  const handleSelect = (option) => {
    const isSelected = selectedItems.some((item) => item._id === option._id);
    if (!isSelected) {
      onToggle(option);
    }
    setSearchTerm("");
    setIsOpen(false);
  };

  const filteredOptions = options.filter((option) => {
    const isNotSelected = !selectedItems.some((item) => item._id === option._id);
    const matchesSearch =
      option[displayKey]?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (secondaryKey &&
        option[secondaryKey]?.toLowerCase().includes(searchTerm.toLowerCase())) ||
      additionalKeys.some((key) =>
        option[key]?.toString().toLowerCase().includes(searchTerm.toLowerCase())
      );
    return isNotSelected && matchesSearch;
  });

  const labelStyle = {
    color: "#265768",
    fontFamily: "'Mulish', sans-serif",
    fontSize: "14px",
    fontWeight: "500",
    marginBottom: "8px",
  };

  const selectStyle = {
    width: "100%",
    height: "40px",
    border: "1.5px solid #DFDFDF",
    borderRadius: "8px",
    fontSize: "14px",
    fontFamily: "'Mulish', sans-serif",
    color: "#000000",
    padding: "0 12px",
    boxSizing: "border-box",
    cursor: "pointer",
    background: "white",
    appearance: "none",
    backgroundImage: `url("data:image/svg+xml,%3Csvg width='12' height='8' viewBox='0 0 12 8' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1.5L6 6.5L11 1.5' stroke='%23666' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E")`,
    backgroundRepeat: "no-repeat",
    backgroundPosition: "right 12px center",
    paddingRight: "35px",
  };

  return (
    <div style={{ position: "relative" }} ref={dropdownRef}>
      <div style={labelStyle}>{label}</div>

      <div
        onClick={() => setIsOpen(!isOpen)}
        style={{
          ...selectStyle,
          display: "flex",
          alignItems: "center",
          color: selectedItems.length === 0 ? "#999" : "#000",
        }}
      >
        {selectedItems.length === 0
          ? placeholder
          : `${selectedItems.length} selected`}
      </div>

      {isOpen && (
        <div
          style={{
            position: "absolute",
            top: "100%",
            left: 0,
            right: 0,
            marginTop: "4px",
            background: "white",
            border: "1.5px solid #4BACCE",
            borderRadius: "8px",
            maxHeight: "250px",
            overflowY: "auto",
            zIndex: 1000,
            boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
          }}
        >
          <div
            style={{
              padding: "8px",
              borderBottom: "1px solid #f0f0f0",
              position: "sticky",
              top: 0,
              background: "white",
            }}
          >
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search..."
              autoFocus
              style={{
                width: "100%",
                padding: "6px 10px",
                border: "1px solid #DFDFDF",
                borderRadius: "6px",
                fontSize: "13px",
                fontFamily: "'Mulish', sans-serif",
                outline: "none",
              }}
            />
          </div>

          <div>
            {filteredOptions.length === 0 ? (
              <div
                style={{
                  padding: "12px",
                  textAlign: "center",
                  color: "#999",
                  fontSize: "13px",
                  fontFamily: "'Mulish', sans-serif",
                }}
              >
                No options available
              </div>
            ) : (
              filteredOptions.map((option) => (
                <div
                  key={option._id}
                  onClick={() => handleSelect(option)}
                  style={{
                    padding: "10px 12px",
                    cursor: "pointer",
                    borderBottom: "1px solid #f5f5f5",
                    fontFamily: "'Mulish', sans-serif",
                    fontSize: "14px",
                    transition: "background 0.15s",
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "#E8F4F8";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "white";
                  }}
                >
                  <div style={{ fontWeight: "500", color: "#333" }}>
                    {option[displayKey]}
                  </div>
                  {secondaryKey && option[secondaryKey] && (
                    <div style={{ fontSize: "12px", color: "#666", marginTop: "2px" }}>
                      {option[secondaryKey]}
                    </div>
                  )}
                  {additionalKeys.length > 0 && (
                    <div style={{ fontSize: "12px", color: "#666", marginTop: "2px" }}>
                      {additionalKeys
                        .filter((key) => option[key])
                        .map((key) => option[key])
                        .join(" • ")}
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================
// MAIN COMPONENT
// ============================================
export default function ManualEntryBatch() {
  const scrollRef = useRef(null);
  const fileInputRef = useRef(null);

  const [batches, setBatches] = useState([]);
  const [subjectsList, setSubjectsList] = useState([]);
  const [facultiesList, setFacultiesList] = useState([]);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editingId, setEditingId] = useState(null);

  const [showPopup, setShowPopup] = useState(false);
  const [popupTitle, setPopupTitle] = useState("");
  const [popupItems, setPopupItems] = useState([]);

  const [form, setForm] = useState({
    course: "",
    department: "",
    name: "",
    strength: "",
    semester: "",
    subjects: [],
    faculties: [],
  });

  const navigate = useNavigate();

  const normalizeArrayResponse = (res) => {
    if (!res) return [];
    if (Array.isArray(res)) return res;
    if (res?.success && Array.isArray(res?.data)) return res.data;
    if (Array.isArray(res?.data)) return res.data;
    if (Array.isArray(res?.subjects)) return res.subjects;
    if (Array.isArray(res?.faculties)) return res.faculties;
    if (Array.isArray(res?.batches)) return res.batches;
    return [];
  };

  const openListPopup = (title, items) => {
    setPopupTitle(title);
    setPopupItems(Array.isArray(items) ? items : []);
    setShowPopup(true);
  };

  useEffect(() => {
    loadAll();
  }, []);

  const loadAll = async () => {
    await Promise.all([loadSubjects(), loadFaculties(), loadBatches()]);
  };

  const loadSubjects = async () => {
    try {
      const res = await getSubjects();
      setSubjectsList(normalizeArrayResponse(res));
    } catch (err) {
      setSubjectsList([]);
    }
  };

  const loadFaculties = async () => {
    try {
      const res = await getFaculties();
      setFacultiesList(normalizeArrayResponse(res));
    } catch (err) {
      setFacultiesList([]);
    }
  };

  const loadBatches = async () => {
    try {
      setLoading(true);
      setError("");
      const res = await getBatches();
      setBatches(normalizeArrayResponse(res));
    } catch (err) {
      setError(err.message || "Failed to load batches");
      setBatches([]);
    } finally {
      setLoading(false);
    }
  };

  const triggerFile = () => fileInputRef.current?.click();

  const handleFileChange = (e) => {
    const f = e.target.files && e.target.files[0];
    if (!f) return;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const toggleSubject = (subject) => {
    setForm((prev) => {
      const exists = prev.subjects.find((s) => s._id === subject._id);
      if (exists) {
        return { ...prev, subjects: prev.subjects.filter((s) => s._id !== subject._id) };
      } else {
        return { ...prev, subjects: [...prev.subjects, subject] };
      }
    });
  };

  const toggleFaculty = (faculty) => {
    setForm((prev) => {
      const exists = prev.faculties.find((f) => f._id === faculty._id);
      if (exists) {
        return { ...prev, faculties: prev.faculties.filter((f) => f._id !== faculty._id) };
      } else {
        return { ...prev, faculties: [...prev.faculties, faculty] };
      }
    });
  };

  const removeSubject = (subjectId) => {
    setForm((prev) => ({
      ...prev,
      subjects: prev.subjects.filter((s) => s._id !== subjectId),
    }));
  };

  const removeFaculty = (facultyId) => {
    setForm((prev) => ({
      ...prev,
      faculties: prev.faculties.filter((f) => f._id !== facultyId),
    }));
  };

  const handleAddBatch = async () => {
    if (!form.course || !form.department || !form.name || !form.strength || !form.semester) {
      setError("Please fill all required fields");
      return;
    }
    if (form.subjects.length === 0) {
      setError("Please select at least one subject");
      return;
    }

    try {
      setLoading(true);
      setError("");
      const code = `${form.department}_${Number(form.semester)}_${form.name}_2025`;
      const payload = {
        name: form.name,
        course: form.course,
        code,
        semester: Number(form.semester),
        department: form.department,
        strength: Number(form.strength),
        subjects: form.subjects.map((subject) => subject._id),
      };

      let res;
      if (editingId) res = await updateBatch(editingId, payload);
      else res = await addBatchAPI(payload);

      if (res?.success || res?._id) {
        await loadBatches();
        resetForm();
      } else {
        throw new Error(res?.message || "Failed to save batch");
      }
    } catch (err) {
      setError(err.message || "Failed to save batch");
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (batch) => {
    const subjects = batch.raw?.subjects || batch.subjects || [];
    const subjectsFromBatch = Array.isArray(subjects)
      ? subjects.map((s) => (typeof s.subject === "object" ? s.subject : s)).filter(Boolean)
      : [];
    const facultiesFromBatch = Array.isArray(subjects)
      ? subjects.map((s) => (typeof s.faculty === "object" ? s.faculty : s)).filter(Boolean)
      : [];

    setForm({
      course: batch.course || batch.degree || "",
      department: batch.department || "",
      name: batch.section || batch.name || batch.raw?.name || "",
      strength: (batch.capacity || batch.strength || batch.raw?.strength)?.toString?.() || "",
      semester: batch.semester?.toString?.() || "",
      subjects: subjectsFromBatch,
      faculties: facultiesFromBatch,
    });
    setEditingId(batch._id);
    setError("");
  };

  const handleDeleteBatch = async (id) => {
    const result = await Swal.fire({
      text: "Are you sure you want to delete this batch?",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#DC3545",
      cancelButtonColor: "#4BACCE",
      confirmButtonText: "Yes",
    });

    if (!result.isConfirmed) return;

    try {
      setLoading(true);
      setError("");
      const res = await deleteBatch(id);
      if (res?.success) await loadBatches();
    } catch (err) {
      Swal.fire({
        icon: "error",
        text: err.message || "Failed to delete batch",
        confirmButtonColor: "#4BACCE",
      });
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setForm({
      course: "",
      department: "",
      name: "",
      strength: "",
      semester: "",
      subjects: [],
      faculties: [],
    });
    setEditingId(null);
    setError("");
  };

  const inputStyle = {
    width: "100%",
    height: "40px",
    borderRadius: "8px",
    border: "1.5px solid #DFDFDF",
    fontSize: "14px",
    fontFamily: "'Mulish', sans-serif",
    color: "#000000",
    background: "#FFFFFF",
    padding: "0 12px",
    boxSizing: "border-box",
  };

  const labelStyle = {
    color: "#265768",
    fontFamily: "'Mulish', sans-serif",
    fontSize: "14px",
    fontWeight: "500",
    marginBottom: "8px",
  };

  return (
    <div className="h-screen overflow-hidden bg-[#F3F6FB]">
      <div className="w-full h-full pb-0">
        <div
          className="bg-white rounded-[10px] shadow-sm border relative w-full h-full"
          style={{ borderColor: "#e8e8e8" }}
        >
          <div className="px-6 pt-4 pb-4">
            {/* HEADER */}
            <div className="flex justify-between items-start mb-6">
              <div
                className="text-3xl font-['Playfair_Display'] font-bold text-[#6b6b6b]"
                style={{ textShadow: "0px 6px 6px rgba(0, 0, 0, 0.25)" }}
              >
                Ezey
              </div>
              <button
                type="button"
                onClick={() => navigate("/form")}
                className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 transition"
                aria-label="Close"
              >
                <BackButton />
              </button>
            </div>

            {/* TITLE ROW */}
            <div className="flex justify-between items-end mb-3">
              <div className="flex items-center gap-2">
                <svg width="18" height="20" viewBox="0 0 18 20" fill="none">
                  <path
                    d="M16 16H6C5.46957 16 4.96086 15.7893 4.58579 15.4142C4.21071 15.0391 4 14.5304 4 14V2C4 1.46957 4.21071 0.960859 4.58579 0.585786C4.96086 0.210714 5.46957 0 6 0H7V5L9 3.5L11 5V0H16C16.5304 0 17.0391 0.210714 17.4142 0.585786C17.7893 0.960859 18 1.46957 18 2V14C18 14.5304 17.7893 15.0391 17.4142 15.4142C17.0391 15.7893 16.5304 16 16 16ZM14 18V20H2C1.46957 20 0.960859 19.7893 0.585786 19.4142C0.210714 19.0391 0 18.5304 0 18V4H2V18H14Z"
                    fill="#265768"
                  />
                </svg>
                <h2 className="text-xl font-['Playfair_Display'] font-semibold text-[#265768]">
                  Quick add batch
                </h2>
              </div>
            </div>

            <div
              className="h-[3px] bg-[#0b84d6] rounded w-[calc(100%+48px)] -mx-6 mb-4"
              style={{ boxShadow: "0px 4px 4px 0px rgba(0,0,0,0.25)" }}
            />

            {error && (
              <div className="mb-4 text-center text-red-500 text-sm font-medium">
                {error}
              </div>
            )}

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-12 gap-x-4 gap-y-4 mr-0 lg:mr-8 mb-4">
              <div className="lg:col-span-3">
                <div style={labelStyle}>Degree</div>
                <input
                  name="course"
                  value={form.course}
                  onChange={handleChange}
                  placeholder="e.g. BCA"
                  disabled={loading}
                  style={inputStyle}
                  className="custom-input"
                />
              </div>

              <div className="lg:col-span-3">
                <div style={labelStyle}>Department</div>
                <input
                  name="department"
                  value={form.department}
                  onChange={handleChange}
                  placeholder="e.g. Computer Science"
                  disabled={loading}
                  style={inputStyle}
                  className="custom-input"
                />
              </div>

              <div className="lg:col-span-3">
                <div style={labelStyle}>Section</div>
                <input
                  name="name"
                  value={form.name}
                  onChange={handleChange}
                  placeholder="e.g. A"
                  disabled={loading}
                  style={inputStyle}
                  className="custom-input"
                />
              </div>

              <div className="lg:col-span-3">
                <div style={labelStyle}>Strength</div>
                <input
                  name="strength"
                  value={form.strength}
                  onChange={handleChange}
                  placeholder="e.g. 60"
                  type="number"
                  disabled={loading}
                  style={inputStyle}
                  className="custom-input"
                />
              </div>

              <div className="lg:col-span-3">
                <div style={labelStyle}>Semester</div>
                <input
                  name="semester"
                  value={form.semester}
                  onChange={handleChange}
                  placeholder="e.g. 1"
                  disabled={loading}
                  style={inputStyle}
                  className="custom-input"
                />
              </div>

              <div className="lg:col-span-3">
                <MultiSelect
                  label="Assigned subjects"
                  placeholder="Select subjects"
                  options={subjectsList}
                  selectedItems={form.subjects}
                  onToggle={toggleSubject}
                  onRemove={removeSubject}
                  displayKey="name"
                  secondaryKey="code"
                  additionalKeys={["department", "semester", "section", "type", "course"]}
                />
              </div>

              <div className="lg:col-span-3 flex items-end justify-start lg:justify-end">
                <button
                  onClick={handleAddBatch}
                  disabled={loading}
                  style={{
                    fontSize: "12px",
                    color: "rgb(77, 172, 206)",
                    background: "transparent",
                    border: "none",
                    cursor: "pointer",
                    fontFamily: "'Mulish', sans-serif",
                    position: "relative",
                    whiteSpace: "nowrap",
                    opacity: loading ? 0.6 : 1,
                  }}
                  className="flex items-center text-[12px] font-['Mulish'] text-[#9CA3AF] after:content-['']
                    after:absolute after:left-0 after:-bottom-[2px]
                    after:h-[1px] after:w-full after:bg-[#4A9FB5]
                    after:scale-x-0 after:origin-left
                    after:transition-transform after:duration-300
                    hover:after:scale-x-100 hover:text-[#4BACCE] whitespace-nowrap transition-colors"
                >
                  {loading ? "Adding..." : "+ Add batch"}
                </button>
              </div>
            </div>

            <div className="w-full h-[2px] bg-[#D9D9D9] mb-6" />

            {loading && batches.length === 0 ? (
              <div
                className="mt-6 border rounded-lg flex flex-col justify-center items-center gap-1 px-4"
                style={{ height: "380px", borderColor: "#DFDFDF" }}
              >
                <div className="text-gray-500">Loading batches...</div>
              </div>
            ) : batches.length === 0 ? (
              <div
                className="mt-4 border rounded-lg flex flex-col justify-center items-center gap-1 px-4"
                style={{ height: "380px", borderColor: "#DFDFDF" }}
              >
                <img
                  src={nodata}
                  alt="No Data"
                  className="w-full max-w-[380px] h-auto object-contain mt-2 mb-[-10px]"
                />
                <div
                  className="text-[24px] font-['Playfair_Display'] font-bold text-[#aeadad]"
                  style={{ fontFamily: "Playfair Display, serif" }}
                >
                  No Data !
                </div>
              </div>
            ) : (
              <div
                style={{
                  border: "1.5px solid #DFDFDF",
                  borderRadius: "12px",
                  overflow: "auto",
                  background: "white",
                  maxHeight: "500px",
                }}
              >
                <div style={{ minWidth: "1000px" }}>
                  {/* Table Header */}
                  <div
                    style={{
                      display: "grid",
                      gridTemplateColumns: "50px 1fr 1fr 1fr 1fr 1fr 1.2fr 100px",
                      background: "#F8F9FA",
                      borderBottom: "2px solid #4BACCE",
                      fontFamily: "'Mulish', sans-serif",
                      fontSize: "13px",
                      fontWeight: "700",
                      color: "#265768",
                      position: "sticky",
                      top: 0,
                      zIndex: 10,
                    }}
                  >
                    <div style={{ padding: "14px 16px" }}>S.No</div>
                    <div style={{ padding: "14px 16px" }}>Degree / Course</div>
                    <div style={{ padding: "14px 16px" }}>Department</div>
                    <div style={{ padding: "14px 16px" }}>Capacity</div>
                    <div style={{ padding: "14px 16px" }}>Semester</div>
                    <div style={{ padding: "14px 16px" }}>Section</div>
                    <div style={{ padding: "14px 16px" }}>Assigned Subjects</div>
                    <div style={{ padding: "14px 16px", textAlign: "center" }}>Actions</div>
                  </div>

                  {/* Table Rows */}
                  <div>
                    {batches.map((batch, index) => {
                      const subjects = batch.raw?.subjects || batch.subjects || [];

                      return (
                        <div
                          key={batch._id || `batch-${index}`}
                          style={{
                            display: "grid",
                            gridTemplateColumns: "50px 1fr 1fr 1fr 1fr 1fr 1.2fr 100px",
                            borderBottom:
                              index < batches.length - 1
                                ? "1px solid #E8E8E8"
                                : "none",
                            fontFamily: "'Mulish', sans-serif",
                            fontSize: "13px",
                            color: "#333",
                            alignItems: "center",
                          }}
                        >
                          {/* S.No */}
                          <div style={{ padding: "14px 16px" }}>{index + 1}</div>

                          <div style={{ padding: "14px 16px" }}>
                            {batch.course || batch.degree || "-"}
                          </div>
                          <div style={{ padding: "14px 16px" }}>
                            {batch.department || "-"}
                          </div>
                          <div style={{ padding: "14px 16px" }}>
                            {batch.capacity || batch.strength || batch.raw?.strength || "-"}
                          </div>
                          <div style={{ padding: "14px 16px" }}>
                            {batch.semester || "-"}
                          </div>
                          <div style={{ padding: "14px 16px" }}>
                            {batch.section || batch.name || batch.raw?.name || "-"}
                          </div>
                          <div style={{ padding: "14px 16px" }}>
                            {subjects.length > 0 ? (
                              <button
                                onClick={() =>
                                  openListPopup(
                                    "Assigned Subjects",
                                    subjects.map((p) => p.subject)
                                  )
                                }
                                style={{
                                  color: "#4BACCE",
                                  background: "none",
                                  border: "none",
                                  cursor: "pointer",
                                  fontSize: "13px",
                                  fontFamily: "'Mulish', sans-serif",
                                  textDecoration: "underline",
                                }}
                              >
                                See List ({subjects.length})
                              </button>
                            ) : (
                              "-"
                            )}
                          </div>
                          <div
                            style={{
                              padding: "14px 16px",
                              display: "flex",
                              justifyContent: "center",
                              gap: "12px",
                            }}
                          >
                            <button
                              onClick={() => handleEdit(batch)}
                              disabled={loading}
                              style={{
                                background: "none",
                                border: "none",
                                cursor: "pointer",
                                padding: "4px",
                              }}
                              title="Edit"
                            >
                              <Edit2 size={16} color="#4BACCE" />
                            </button>
                            <button
                              onClick={() => handleDeleteBatch(batch._id)}
                              disabled={loading}
                              style={{
                                background: "none",
                                border: "none",
                                cursor: "pointer",
                                padding: "4px",
                              }}
                              title="Delete"
                            >
                              <Trash2 size={16} color="#DC3545" />
                            </button>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}
          </div>

          {showPopup && (
            <div
              className="fixed inset-0 z-[999] flex items-center justify-center"
              style={{ background: "rgba(0,0,0,0.35)" }}
              onClick={() => setShowPopup(false)}
            >
              <div
                className="bg-white rounded-[10px] shadow-lg border"
                style={{
                  width: "420px",
                  maxHeight: "420px",
                  overflow: "hidden",
                  borderColor: "#e8e8e8",
                }}
                onClick={(e) => e.stopPropagation()}
              >
                <div className="flex items-center justify-between px-5 py-3 border-b">
                  <div className="text-[16px] font-semibold text-[#265768]">
                    {popupTitle}
                  </div>
                  <button onClick={() => setShowPopup(false)}>
                    <X size={18} color="#265768" />
                  </button>
                </div>

                <div className="p-4 overflow-y-auto" style={{ maxHeight: "340px" }}>
                  {popupItems.length === 0 ? (
                    <div className="text-center text-gray-400 py-10">No data</div>
                  ) : (
                    <ul className="space-y-2">
                      {popupItems.map((x, i) => (
                        <li
                          key={`${x?._id || "item"}-${i}`}
                          className="text-[13px] text-[#265768] border rounded px-3 py-2"
                          style={{ borderColor: "#DFDFDF" }}
                        >
                          {popupTitle === "Assigned Subjects"
                            ? `${x?.name || "-"}${x?.code ? ` (${x.code})` : ""}`
                            : `${x?.name || "-"}${x?.email ? ` (${x.email})` : ""}`}
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
              </div>
            </div>
          )}

          <style>{`
            .custom-input:focus {
              border: 1.5px solid #0b84d6 !important;
              box-shadow: 0 0 0 3px rgba(11, 132, 214, 0.2);
              outline: none;
            }
            input::placeholder, select::placeholder {
              color: #999999;
              opacity: 1;
            }
            select option { padding: 8px; }
            div[style*="overflow: auto"]::-webkit-scrollbar { width: 8px; height: 8px; }
            div[style*="overflow: auto"]::-webkit-scrollbar-track { background: #f1f1f1; border-radius: 4px; }
            div[style*="overflow: auto"]::-webkit-scrollbar-thumb { background: #4BACCE; border-radius: 4px; }
            div[style*="overflow: auto"]::-webkit-scrollbar-thumb:hover { background: #265768; }
            div[style*="overflow: auto"]::-webkit-scrollbar-corner { background: #f1f1f1; }
          `}</style>
        </div>
      </div>
    </div>
  );
}











