import React, { useRef, useState, useEffect } from "react";
import { Edit2, Trash2, X } from "lucide-react";
import nodata from "../../assets/images/nodataa.png";
import { useNavigate } from "react-router-dom";
import {
  getSubjects,
  addSubjectAPI,
  deleteSubjectAPI,
  updateSubjectAPI, bulkUploadSubjects
} from "../../services/api";
import BackButton from "../../components/backbutton";
import Swal from "sweetalert2";
import DataEntryTable from "../../components/ui/manualEntryTable";



// =============================
// COMPONENT
// =============================
export default function ManualEntrySubject() {
  const fileInputRef = useRef(null);
  const navigate = useNavigate();

  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [editingId, setEditingId] = useState(null);

  const [form, setForm] = useState({
    name: "",
    code: "",
    department: "",
    section: "",
    semester: "",
    hrsWeek: "",
    type: "",
    course: "",
    isElective: false,
  });

  const inputStyle = {
    width: "274.5px",
    height: "40px",
    borderRadius: "15px",
    border: "1.5px solid #DFDFDF",
    fontSize: "14px",
    fontFamily: "'Mulish', sans-serif",
    color: "#000000",
    background: "#FFFFFF",
    padding: "0 12px",
    boxSizing: "border-box",
  };

  const triggerFile = () => fileInputRef.current?.click();

  const handleFileChange = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const validTypes = [
      "text/csv",
      "application/vnd.ms-excel",
      "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    ];

    if (
      !validTypes.includes(file.type) &&
      !file.name.match(/\.(csv|xlsx|xls)$/i)
    ) {
      Swal.fire({
        icon: "warning",
        text: "Please upload a valid CSV or XLSX file",
        confirmButtonColor: "#4BACCE",
      });

      e.target.value = "";
      return;
    }

    try {
      setLoading(true);
      setError("");

      const response = await bulkUploadSubjects(file);

      if (response?.success || Array.isArray(response)) {
        await fetchSubjects();
      }
    } catch (err) {
      Swal.fire({
        icon: "error",
        text: "Failed to upload file: " + (err.message || "Unknown error"),
        confirmButtonColor: "#4BACCE",
      });
    } finally {
      setLoading(false);
      e.target.value = "";
    }
  };


  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm((prev) => ({ ...prev, [name]: type === "checkbox" ? checked : value }));
  };

  const fetchSubjects = async () => {
    try {
      setLoading(true);
      setError("");

      const response = await getSubjects();

      const mapped = (response?.data || []).map((s) => ({
        _id: s._id,
        name: s.name,
        code: s.code,
        department: s.department,
        semester: s.semester || "--",
        section: s.section || "--",
        type: s.type,
        hrsWeek: s.hoursPerWeek,
        course: s.course || "",
        isElective: s.isElective || false,
      }));

      setSubjects(mapped);
    } catch (err) {
      setError(err.message || "Failed to load subjects");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSubjects();
  }, []);

  const saveSubject = async () => {
    if (!form.name || !form.code) {
      setError("Please enter Subject name and Subject code");
      return;
    }

    if (!form.type || !["theory", "lab"].includes(form.type)) {
      setError("Please select valid type (Theory / Practical)");
      return;
    }

    try {
      setLoading(true);
      setError("");

      const payload = {
        name: form.name,
        code: form.code,
        department: form.department,
        course: form.course,
        section: form.section,
        semester: Number(form.semester),
        type: form.type,
        isElective: form.isElective,
        hoursPerWeek: Number(form.hrsWeek || 0),
      };

      let response;
      if (editingId) response = await updateSubjectAPI(editingId, payload);
      else response = await addSubjectAPI(payload);

      if (response?.success || response?._id) {
        await fetchSubjects();
        setForm({
          name: "",
          code: "",
          department: "",
          section: "",
          semester: "",
          hrsWeek: "",
          type: "",
          course: "",
          isElective: false,
        });
        setEditingId(null);
      } else {
        setError(response.message || "Failed to save subject");
      }
    } catch (err) {
      setError(err.message || "Failed to save subject");
    } finally {
      setLoading(false);
    }
  };

  const handleEditSubject = (item) => {
    setEditingId(item._id);
    setForm({
      name: item.name || "",
      code: item.code || "",
      department: item.department || "",
      section: item.section === "--" ? "" : item.section || "",
      semester: item.semester === "--" ? "" : item.semester || "",
      hrsWeek: item.hrsWeek?.toString?.() || "",
      type: item.type || "",
      course: item.course || "",
      isElective: item.isElective || false,
    });
    setError("");
  };

  const cancelEdit = () => {
    setEditingId(null);
    setForm({
      name: "",
      code: "",
      department: "",
      section: "",
      semester: "",
      hrsWeek: "",
      type: "",
      course: "",
      isElective: false,
    });
    setError("");
  };

  const handleDeleteSubject = async (id) => {
    const result = await Swal.fire({
      text: "Are you sure you want to delete this subject?",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#F04438",
      cancelButtonColor: "#4BACCE",
      confirmButtonText: "Yes",
    });

    if (!result.isConfirmed) return;

    try {
      setLoading(true);
      setError("");

      const response = await deleteSubjectAPI(id);

      if (response.success || response?.status) await fetchSubjects();
    } catch (err) {
      Swal.fire({
        icon: "error",
        text: "Failed to delete subject: " + err.message,
        confirmButtonColor: "#4BACCE",
      });
    } finally {
      setLoading(false);
    }
  };


  return (
    <div className="h-screen overflow-hidden bg-[#F3F6FB]">
      <div className="w-full h-full pb-0">
        <div
          className="bg-white rounded-[10px] shadow-sm border relative w-full h-full"
          style={{
            borderColor: "#e8e8e8",
          }}
        >
          <div className="px-6 pt-4 pb-4">
            {/* HEADER (Row 1: Logo + Close) */}
            <div className="flex justify-between items-start mb-6">
              <div
                className="text-3xl font-['Playfair_Display'] font-bold text-[#6b6b6b]"
                style={{ textShadow: "0px 6px 6px rgba(0, 0, 0, 0.25)" }}
              >
                Ezey
              </div>
              <button
                type="button"
                onClick={() => navigate("/form")}
                className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 transition"
                aria-label="Close"
              >
                <BackButton />
              </button>
            </div>

            {/* TITLE ROW (Row 2: Title + Upload) */}
            <div className="flex justify-between items-end mb-3">
              <div className="flex items-center gap-2">
                <svg width="18" height="20" viewBox="0 0 18 20" fill="none">
                  <path
                    d="M16 16H6C5.46957 16 4.96086 15.7893 4.58579 15.4142C4.21071 15.0391 4 14.5304 4 14V2C4 1.46957 4.21071 0.960859 4.58579 0.585786C4.96086 0.210714 5.46957 0 6 0H7V5L9 3.5L11 5V0H16C16.5304 0 17.0391 0.210714 17.4142 0.585786C17.7893 0.960859 18 1.46957 18 2V14C18 14.5304 17.7893 15.0391 17.4142 15.4142C17.0391 15.7893 16.5304 16 16 16ZM14 18V20H2C1.46957 20 0.960859 19.7893 0.585786 19.4142C0.210714 19.0391 0 18.5304 0 18V4H2V18H14Z"
                    fill="#265768"
                  />
                </svg>
                <h2 className="text-xl font-['Playfair_Display'] font-semibold text-[#265768]">
                  Quick add subject
                </h2>
              </div>
            </div>

            <div
              className="h-[3px] bg-[#0b84d6] rounded w-[calc(100%+48px)] -mx-6"
              style={{ boxShadow: "0px 4px 4px 0px rgba(0,0,0,0.25)" }}
            />

            {/* FORM */}
            <div className="mt-6">
              <div className="grid grid-cols-12 gap-x-2 gap-y-6 mr-8">
                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Subject name
                  </div>
                  <input name="name" value={form.name} onChange={handleChange} placeholder="e.g. DAA" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Subject code
                  </div>
                  <input name="code" value={form.code} onChange={handleChange} placeholder="e.g. CS201" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Department
                  </div>
                  <input name="department" value={form.department} onChange={handleChange} placeholder="e.g. CSE" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Course
                  </div>
                  <input name="course" value={form.course} onChange={handleChange} placeholder="e.g. BTECH" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Section
                  </div>
                  <input name="section" value={form.section} onChange={handleChange} placeholder="e.g. A" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Semester
                  </div>
                  <input name="semester" value={form.semester} onChange={handleChange} placeholder="e.g. 4" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Hrs/Week
                  </div>
                  <input name="hrsWeek" value={form.hrsWeek} onChange={handleChange} placeholder="e.g. 4" style={inputStyle} className="custom-input" />
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Type
                  </div>
                  <select name="type" value={form.type} onChange={handleChange} style={inputStyle} className="custom-input">
                    <option value="">Select Type</option>
                    <option value="theory">Theory</option>
                    <option value="lab">Practical / Lab</option>
                  </select>
                </div>

                <div className="col-span-3">
                  <div className="text-xs mb-1" style={{ color: "#265768", fontSize: "14px" }}>
                    Is Elective?
                  </div>
                  <select
                    name="isElective"
                    value={form.isElective ? "true" : "false"}
                    onChange={(e) => handleChange({ target: { name: "isElective", value: e.target.value === "true", type: "select" } })}
                    style={inputStyle}
                    className="custom-input"
                  >
                    <option value="false">No</option>
                    <option value="true">Yes</option>
                  </select>
                </div>

                <div className="col-span-3 flex items-end">
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", width: "100%" }}>
                    <button
                      onClick={saveSubject}
                      disabled={loading}
                      className="after:content-['']
              after:absolute after:left-0 after:-bottom-[2px]
              after:h-[1px] after:w-full after:bg-[#4A9FB5]
              after:scale-x-0 after:origin-left
              after:transition-transform after:duration-300
              hover:after:scale-x-100"
                      style={{
                        fontSize: "12px",
                        color: "rgb(77, 172, 206)",
                        background: "transparent",
                        border: "none",
                        cursor: "pointer",
                        fontFamily: "'Mulish', sans-serif",
                        position: "relative",
                        whiteSpace: "nowrap",
                        opacity: loading ? 0.6 : 1,
                        textAlign: "left",
                      }}
                    >
                      {editingId ? (loading ? "Updating..." : "+ Update subject") : loading ? "Adding..." : "+ Add subject"}
                    </button>
                    {editingId && (
                      <button
                        onClick={cancelEdit}
                        style={{
                          fontSize: "12px",
                          color: "#F04438",
                          background: "transparent",
                          border: "none",
                          cursor: "pointer",
                          fontFamily: "'Mulish', sans-serif",
                          textAlign: "left",
                        }}
                      >
                        Cancel Edit
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>

            <div className="w-full h-[2px] bg-[#D9D9D9] mt-7" />

            {error && (
              <div className="mt-3 text-center text-red-500 text-sm font-medium">
                {error}
              </div>
            )}

            {/* TABLE */}
            {subjects.length === 0 ? (
              <div
                className="mt-4 border rounded-lg flex flex-col justify-center items-center gap-1 px-4"
                style={{ height: "380px", borderColor: "#DFDFDF" }}
              >
                <img
                  src={nodata}
                  alt="No Data"
                  className="w-full max-w-[380px] h-auto object-contain mt-2 mb-[-10px]"
                />
                <div
                  className="text-[24px] font-['Playfair_Display'] font-bold text-[#aeadad]"
                  style={{ fontFamily: "Playfair Display, serif" }}
                >
                  No Data !
                </div>
              </div>
            ) : (
              <div className="mt-6 pb-6">
                {/* <div
                  className="bg-white w-full relative"
                  style={{
                    width: "100%",
                    height: "325px",
                    borderRadius: "12.23px",
                    border: "1.83px solid #DFDFDF",
                    overflow: "hidden",
                  }}
                >
                  <div className="px-8 pt-4 pb-2 bg-white mr-3">
                    <div className="flex items-center text-[14px] font-medium" style={{ color: "#265768", fontFamily: "'Mulish', sans-serif" }}>
                      <div className="flex-1 text-center">Subject Name</div>
                      <div className="flex-1 text-center">Subject Code</div>
                      <div className="flex-1 text-center">Department</div>
                      <div className="flex-1 text-center">Semester</div>
                      <div className="flex-1 text-center">Section</div>
                      <div className="flex-1 text-center">Type</div>
                      <div className="flex-1 text-center">Hrs/Week</div>
                      <div className="flex-1 text-center">Actions</div>
                    </div>

                    <div className="mt-3 h-[3px] rounded" style={{ background: "#0b84d6", boxShadow: "0px 4px 4px 0px rgba(0,0,0,0.25)" }} />
                  </div>

                  <div className="overflow-y-auto custom-scroll mr-3" style={{ maxHeight: "300px" }}>
                    <div className="px-8">
                      {subjects.map((item, idx) => (
                        <div key={item._id || idx} className="flex items-center py-3.5 hover:bg-gray-50 transition" style={{ borderBottom: "3px solid #D9D9D9" }}>
                          <div className="flex-1 text-[13px] font-medium text-[#265768] text-center">{item.name}</div>
                          <div className="flex-1 text-[13px] text-[#265768] text-center">{item.code}</div>
                          <div className="flex-1 text-[13px] text-[#265768] truncate text-center">{item.department}</div>
                          <div className="flex-1 text-[13px] text-[#265768] text-center">{item.semester}</div>
                          <div className="flex-1 text-[13px] text-[#265768] text-center">{item.section}</div>
                          <div className="flex-1 text-[13px] text-[#265768] text-center">{item.type}</div>
                          <div className="flex-1 text-[13px] text-[#265768] text-center">{item.hrsWeek}</div>

                          <div className="flex-1 flex items-center justify-center gap-3">
                            <button onClick={() => handleEditSubject(item)} className="text-[#C0C6D0] hover:text-[#1A8FE3] transition" title="Edit">
                              <Edit2 size={15} />
                            </button>
                            <button onClick={() => handleDeleteSubject(item._id)} className="text-[#C0C6D0] hover:text-[#F04438] transition" title="Delete">
                              <Trash2 size={15} />
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div> */}
                <DataEntryTable
  height="calc(100vh - 460px)"
  columns={[
    { key: "name", label: "Subject Name" },
    { key: "code", label: "Subject Code" },
    { key: "department", label: "Department" },
    { key: "semester", label: "Semester" },
    { key: "section", label: "Section" },
    { key: "type", label: "Type" },
    { key: "hrsWeek", label: "Hrs/Week" },
  ]}
>
  {subjects.map((item, idx) => (
    <tr
      key={item._id || idx}
      className={`text-sm border-b border-[#ECF0F4] hover:bg-[#F7FAFF] transition ${
        idx === subjects.length - 1 ? "border-b-0" : ""
      }`}
    >
      <td className="py-5 text-center text-[#4C5968]">{item.name}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.code}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.department}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.semester}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.section}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.type}</td>
      <td className="py-5 text-center text-[#4C5968]">{item.hrsWeek}</td>

      <td className="py-5">
        <div className="flex justify-center gap-3">
          <button
            onClick={() => handleEditSubject(item)}
            className="text-[#C0C6D0] hover:text-[#1A8FE3]"
          >
            <Edit2 size={15} />
          </button>

          <button
            onClick={() => handleDeleteSubject(item._id)}
            className="text-[#C0C6D0] hover:text-[#F04438]"
          >
            <Trash2 size={15} />
          </button>
        </div>
      </td>
    </tr>
  ))}
</DataEntryTable>

              </div>
            )}
          </div>
        </div>
      </div>
    </div >
  );
}
